<template>
  <div
    class="ingredient"
    :class="{ checked: checked }"
    v-on:click="
      if (checkbox) {
        checked = !checked;
      }
    "
  >
    <p>
      <button v-if="checkbox" class="check"></button>
      <span class="amount">{{ ingredient.amount }} </span>&nbsp;
      <span class="unit">{{ ingredient.unit }} </span>&nbsp;
      <span class="name">{{ this.toTitleCase(ingredient.name) }}</span>
    </p>
  </div>
</template>

<script>
export default {
  name: 'Ingredient',
  data() {
    return {
      checked: false,
    };
  },
  methods: {
    toTitleCase: function (str) {
      return str.replace(/\w\S*/g, function (txt) {
        return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
      });
    },
  },
  props: {
    ingredient: Object,
    checkbox: Boolean,
  },
};
</script>

<style scoped>
.ingredient {
  margin: 0;
  display: block;
  padding: 20px 10px;
}

.check {
  display: inline-block;
  vertical-align: middle;
  width: 30px;
  height: 30px;
  border-radius: 100%;
  background: var(--background-three);
  border: 5px solid var(--background-three);
  margin-right: 1rem;
  transition: background 0.3s, border 0.3s, transform 0.3s;
}
.ingredient:hover .check {
  transform: scale(1.2);
}
@keyframes check {
  from {
    transform: scale(1.2);
  }

  30% {
    transform: scale(0.9);
  }

  to {
    transform: scale(1.2);
  }
}
.checked .check {
  animation-name: check;
  animation-duration: 0.5s;
  background: var(--color-two);
}
p {
  margin: 0;
}
.amount {
  color: var(--color-two);
}
.unit {
  color: var(--color-two);
}
.amount,
.unit,
.name {
  transition: color 0.3s;
}
.checked .amount,
.checked .unit,
.checked .name {
  color: var(--color-weak);
}
</style>
