<template>
  <div class="recipe" v-on:scroll="scroll()">
    <header :class="{ collapse: collapseHeader }">
      <h2>{{ name }}</h2>
      <div class="progress" :style="{ width: scrollProgress + '%' }"></div>
    </header>
    <h1>Ingredients</h1>
    <Ingredients :ingredients="ingredients"></Ingredients>
    <h1>Instructions</h1>
    <Instructions :instructions="instructions"></Instructions>
    <footer>
      <h2 v-scroll-in="-0.05">All done!</h2>
      <ul v-scroll-in="-0.05">
        <li v-on:click="$router.push('/')">Home</li>
      </ul>
    </footer>
  </div>
</template>

<script>
import Ingredients from '@/components/Ingredients.vue';
import Instructions from '@/components/Instructions.vue';

export default {
  name: 'Recipe',
  data() {
    return {
      name: '',
      ingredients: [],
      instructions: [],
      scrollProgress: 0,
      collapseHeader: false,
      lastScrollPos: 0,
    };
  },
  components: {
    Ingredients,
    Instructions,
  },
  created() {
    window.addEventListener('scroll', this.scroll);
    this.fetchData();
  },
  watch: {
    $route: 'fetchData',
  },
  unmounted: function () {
    window.removeEventListener('scroll', this.scroll);
  },
  methods: {
    fetchData: async function () {
      if (this?.$route?.params?.name) {
        delete require.cache[
          require.resolve(`../assets/${this.$route.params.name}.json`)
        ];
        const data = await require(`../assets/${this.$route.params.name}.json`);
        this.ingredients = [...data.ingredients];
        // add ingredient info to Instructions
        let instructionsBad = [...data.instructions];
        let ingredientDict = {};
        for (let ingredient of this.ingredients) {
          ingredientDict[ingredient.name] = { ...ingredient };
        }
        for (let instruction of instructionsBad) {
          if (instruction?.ingredients?.length > 0) {
            instruction.ingredients = instruction.ingredients.map(function (i) {
              return { ...ingredientDict[i] };
            });
          }
        }
        this.instructions = [...instructionsBad];
        this.name = data.name;
      }
    },
    scroll: function () {
      let winScroll =
        document.body.scrollTop || document.documentElement.scrollTop;
      let height =
        document.documentElement.scrollHeight -
        document.documentElement.clientHeight;
      this.scrollProgress = (winScroll / height) * 100;

      const currentScrollPosition =
        window.pageYOffset || document.documentElement.scrollTop;
      if (currentScrollPosition < 0) {
        return;
      }
      // this.collapseHeader = currentScrollPosition > this.lastScrollPosition;
      this.collapseHeader = currentScrollPosition > 20;
      this.lastScrollPosition = currentScrollPosition;
    },
  },
};
</script>

